package genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program.mapper.VehicleMaintenanceProgramMapper; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program.repository.VehicleMaintenanceProgramRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleMaintenanceProgramService { private final VehicleMaintenanceProgramRepository repository; private final VehicleMaintenanceProgramMapper mapper; public VehicleMaintenanceProgramService(VehicleMaintenanceProgramRepository repository,VehicleMaintenanceProgramMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleMaintenanceProgramResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public VehicleMaintenanceProgramResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("VehicleMaintenanceProgram", String.valueOf(id))); } public VehicleMaintenanceProgramResponse create(VehicleMaintenanceProgramUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleMaintenanceProgramResponse update(UUID id,VehicleMaintenanceProgramUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("VehicleMaintenanceProgram", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("VehicleMaintenanceProgram", String.valueOf(id)); } }
